import pytest
import requests

def test_dispute_at_day_59_accepted_and_day_60_rejected(
    auth_headers, base_url, create_posted_transaction
):
    txn_59 = create_posted_transaction(age_days=59)
    txn_60 = create_posted_transaction(age_days=60)

    payload_59 = {"transaction_id": txn_59["id"], "reason": "unauthorized_charge"}
    resp_59 = requests.post(
        f"{base_url}/disputes", json=payload_59, headers=auth_headers
    )
    assert resp_59.status_code == 201, (
        f"Day-59 dispute should be accepted, got {resp_59.status_code}: {resp_59.text}"
    )
    body_59 = resp_59.json()
    assert body_59.get("provisional_credit", {}).get("applied") is True

    payload_60 = {"transaction_id": txn_60["id"], "reason": "unauthorized_charge"}
    resp_60 = requests.post(
        f"{base_url}/disputes", json=payload_60, headers=auth_headers
    )
    assert resp_60.status_code == 422, (
        f"Day-60 dispute should be rejected, got {resp_60.status_code}: {resp_60.text}"
    )

import pytest
import requests

REASON_CODES = [
    "unauthorized_charge",
    "merchandise_not_received",
    "duplicate_transaction"
]

def test_dispute_decision_table_reason_codes_within_valid_window(
    auth_headers, base_url, create_posted_transaction
):
    dispute_ids = []
    for reason in REASON_CODES:
        txn = create_posted_transaction(age_days=5)
        payload = {"transaction_id": txn["id"], "reason": reason}
        resp = requests.post(
            f"{base_url}/disputes", json=payload, headers=auth_headers
        )
        assert resp.status_code == 201, (
            f"Reason '{reason}' failed: {resp.status_code} {resp.text}"
        )
        body = resp.json()
        assert body.get("provisional_credit", {}).get("applied") is True, (
            f"No provisional credit for reason '{reason}'"
        )
        dispute_ids.append(body["dispute_id"])
    assert len(set(dispute_ids)) == len(REASON_CODES), "Duplicate dispute IDs returned"
